const W=Math.min(innerWidth,480),H=innerHeight;class S extends Phaser.Scene{create(){this.add.rectangle(W/2,H/2,W,H,0x111827);this.add.rectangle(W/2,H/2,6,H,0xffffff,.2);this.add.rectangle(W/2,H/2,W,6,0xffffff,.2);this.v='NS';this.btn=this.add.rectangle(W/2,H-50,180,44,0x2563eb).setInteractive();this.add.text(W/2,H-58,'신호 전환',{fontSize:'20px'}).setOrigin(.5);this.btn.on('pointerdown',()=>this.v=this.v==='NS'?'EW':'NS');this.cars=this.physics.add.group();this.score=0;this.ui=this.add.text(10,10,'Flow:0');this.time.addEvent({delay:600,loop:true,callback:()=>this.spawn()});this.r=this.input.keyboard.addKey('R');}spawn(){const dir=Math.random()>0.5?'N':'W';let x,y,vx=0,vy=0;if(dir==='N'){x=W/2-15;y=-20;vy=120;}else{x=-20;y=H/2+15;vx=120;}const c=this.add.rectangle(x,y,16,10,0xf59e0b);this.physics.add.existing(c);c.dir=dir;c.body.setVelocity(vx,vy);this.cars.add(c);}update(){if(this.r.isDown)this.scene.restart();this.cars.getChildren().forEach(c=>{if(c.dir==='N'&&c.y>H/2-40&&this.v==='EW')c.body.setVelocity(0,0);else if(c.dir==='W'&&c.x>W/2-40&&this.v==='NS')c.body.setVelocity(0,0);else if(c.dir==='N')c.body.setVelocity(0,120);else c.body.setVelocity(120,0);if(c.x>W+20||c.y>H+20){this.score++;this.ui.setText('Flow:'+this.score);c.destroy();if(this.score>=30&&!this.over){this.over=true;this.add.text(W/2,40,'CLEAR R').setOrigin(.5);}}});}}
new Phaser.Game({type:Phaser.AUTO,parent:'game',width:W,height:H,physics:{default:'arcade'},scene:[S]});
